# ===========================================================================
# CORE MODEL FUNCTIONS  (no file I/O)
# ===========================================================================

def snap(value, param):
    if param == 'RQD':
        for lo, hi, idx in RQD_RANGES:
            if lo <= value <= hi:
                return RATINGS['RQD'][idx]
        return RATINGS['RQD'][0] if value < 0 else RATINGS['RQD'][-1]
    return min(RATINGS[param], key=lambda r: abs(r - value))


def rating_to_state(value, param):
    return RATINGS[param].index(value) + 1


def to_states(snapped):
    return {p: [rating_to_state(v, p) for v in vals] for p, vals in snapped.items()}


def make_row_vector(state_list, num_states):
    if not state_list:
        return np.zeros(num_states)
    vec = np.zeros(num_states)
    for s in state_list:
        vec[s - 1] += 1
    return vec / len(state_list)


def compute_predictions(row_vectors):
    predictions = {}
    for param in PARAMS:
        if param not in _EMBEDDED_TPMS:
            continue
        predictions[param] = {}
        rv = row_vectors[param]
        for j, tpm in _EMBEDDED_TPMS[param].items():
            predictions[param][j] = rv @ tpm
    return predictions


def predicted_rating_value(prob_vector, param):
    return float(sum(prob_vector[i] * RATINGS[param][i] for i in range(len(RATINGS[param]))))


def most_probable_rating(prob_vector, param):
    idx = int(np.argmax(prob_vector))
    return RATINGS[param][idx], idx + 1, STATE_LABELS[param][idx]


def interpret(predictions, snapped_inputs):
    pred_ratings = {}
    for param, steps in predictions.items():
        pred_ratings[param] = {}
        fb_vals = snapped_inputs.get(param, [])
        fallback = float(sum(fb_vals) / len(fb_vals)) if fb_vals else float('nan')
        for j, pvec in steps.items():
            if np.sum(pvec) < 1e-9:
                val = fallback
            elif param == 'RQD':
                val = predicted_rating_value(pvec, param)
            else:
                val, _, _ = most_probable_rating(pvec, param)
            pred_ratings[param][j] = val
    return pred_ratings


def compute_q(pred_ratings, j):
    try:
        rqd = pred_ratings['RQD'][j]; jn  = pred_ratings['Jn'][j]
        jr  = pred_ratings['Jr'][j];  ja  = pred_ratings['Ja'][j]
        jw  = pred_ratings['Jw'][j];  srf = pred_ratings['SRF'][j]
        if jn == 0 or ja == 0 or srf == 0:
            return float('nan')
        return (rqd / jn) * (jr / ja) * (jw / srf)
    except KeyError:
        return float('nan')


def classify_q(q):
    if np.isnan(q):   return 'N/A'
    if q < 0.01:      return 'Exceptionally poor'
    if q < 0.1:       return 'Extremely poor'
    if q < 1:         return 'Very poor'
    if q < 4:         return 'Poor'
    if q < 10:        return 'Fair'
    if q < 40:        return 'Good'
    if q < 100:       return 'Very good'
    if q < 400:       return 'Extremely good'
    return 'Exceptionally good'


# ===========================================================================
# EXCEL EXPORT (rich, multi-sheet)
# ===========================================================================

def _tb():
    s = Side(style="thin", color="CCCCCC")
    return Border(left=s, right=s, top=s, bottom=s)


def _fill(hx):
    return PatternFill("solid", fgColor=hx.lstrip("#"))


def _cs(ws, row, col, value, bold=False, fill=None, align="center", fc="000000"):
    c = ws.cell(row=row, column=col, value=value)
    c.font = Font(bold=bold, color=fc, size=10)
    c.alignment = Alignment(horizontal=align, vertical="center")
    c.border = _tb()
    if fill:
        c.fill = fill
    return c


def build_excel(pred_ratings, predictions, input_summary):
    wb = Workbook()
    DK, MID, ALT, WH = "1A1A2E", "16213E", "F4F6FB", "FFFFFF"
    Q_HEX = {
        "Exceptionally poor": "7B0000", "Extremely poor": "C0392B",
        "Very poor": "E74C3C", "Poor": "E67E22", "Fair": "F1C40F",
        "Good": "2ECC71", "Very good": "1ABC9C",
        "Extremely good": "3498DB", "Exceptionally good": "1A5276",
    }

    def qfill(q_val):
        if np.isnan(q_val):
            return None
        return _fill(Q_HEX.get(classify_q(q_val), "FFFFFF"))

    # Sheet 1 — Q Predictions
    ws1 = wb.active
    ws1.title = "Q Predictions"
    ws1.merge_cells("A1:I1")
    c = ws1["A1"]
    c.value = "Markov Chain Q-System Prediction Results"
    c.font = Font(bold=True, size=14, color=WH)
    c.fill = _fill(DK)
    c.alignment = Alignment(horizontal="center", vertical="center")
    ws1.row_dimensions[1].height = 28
    ws1.merge_cells("A2:I2")
    s2 = ws1["A2"]
    s2.value = f"Inputs: {input_summary}"
    s2.font = Font(italic=True, size=9, color="555555")
    s2.alignment = Alignment(horizontal="left")
    for ci, h in enumerate(
        ["Step (j)", "RQD", "Jn", "Jr", "Ja", "Jw", "SRF", "Q Value", "Quality"], 1
    ):
        _cs(ws1, 3, ci, h, bold=True, fill=_fill(MID), fc=WH)
    ws1.row_dimensions[3].height = 20
    for ci, w in enumerate([9, 11, 10, 10, 10, 10, 11, 11, 22], 1):
        ws1.column_dimensions[get_column_letter(ci)].width = w
    for ri, j in enumerate(range(1, 31), 4):
        bg = _fill(ALT) if ri % 2 == 0 else None
        rqd = pred_ratings.get('RQD', {}).get(j, float('nan'))
        jn  = pred_ratings.get('Jn',  {}).get(j, float('nan'))
        jr  = pred_ratings.get('Jr',  {}).get(j, float('nan'))
        ja  = pred_ratings.get('Ja',  {}).get(j, float('nan'))
        jw  = pred_ratings.get('Jw',  {}).get(j, float('nan'))
        srf = pred_ratings.get('SRF', {}).get(j, float('nan'))
        q   = compute_q(pred_ratings, j)
        ql  = classify_q(q)
        vals = [j, round(rqd, 3), round(jn, 3), round(jr, 3),
                round(ja, 3), round(jw, 4), round(srf, 3),
                round(q, 4) if not np.isnan(q) else "N/A", ql]
        for ci, v in enumerate(vals, 1):
            uf  = qfill(q) if ci == 8 and not np.isnan(q) else bg
            ufc = WH if ci == 8 and not np.isnan(q) and ql not in ("Fair", "N/A") else "000000"
            _cs(ws1, ri, ci, v, fill=uf, fc=ufc)
    ws1.freeze_panes = "A4"

    # Sheet 2 — Q Classification Guide
    wsg = wb.create_sheet("Q Classification Guide")
    wsg.merge_cells("A1:D1")
    t = wsg["A1"]
    t.value = "Barton Q-System Rock Mass Classification"
    t.font = Font(bold=True, size=13, color=WH)
    t.fill = _fill(DK)
    t.alignment = Alignment(horizontal="center", vertical="center")
    wsg.row_dimensions[1].height = 26
    for ci, h in enumerate(["Q Range", "Classification", "Conditions", "Support"], 1):
        _cs(wsg, 2, ci, h, bold=True, fill=_fill(MID), fc=WH)
    guide = [
        ("<0.01",   "Exceptionally poor", "Heavy squeezing/flowing",    "Heavy continuous support",   "7B0000"),
        ("0.01-0.1","Extremely poor",     "Very weak highly stressed",  "Systematic bolts+shotcrete", "C0392B"),
        ("0.1-1",   "Very poor",          "Weak jointed squeezing",     "Systematic bolts+mesh",      "E74C3C"),
        ("1-4",     "Poor",               "Fractured faulted rock",     "Spot bolts+shotcrete",       "E67E22"),
        ("4-10",    "Fair",               "Moderately jointed",         "Spot bolts where needed",    "F1C40F"),
        ("10-40",   "Good",               "Competent moderately jointed","Occasional bolts",           "2ECC71"),
        ("40-100",  "Very good",          "Massive few joints",         "Generally unsupported",      "1ABC9C"),
        ("100-400", "Extremely good",     "Near-intact rock",           "No support required",        "3498DB"),
        (">400",    "Exceptionally good", "Massive intact",             "No support required",        "1A5276"),
    ]
    for ri, row_d in enumerate(guide, 3):
        fc = WH if ri != 7 else "000000"
        for ci, v in enumerate(row_d[:4], 1):
            _cs(wsg, ri, ci, v, fill=_fill(row_d[4]), fc=fc)
    for ci, w in enumerate([12, 22, 36, 28], 1):
        wsg.column_dimensions[get_column_letter(ci)].width = w

    # Sheets 3-8 — Per-parameter probability evolution
    for param in PARAMS:
        if param not in predictions:
            continue
        wsp = wb.create_sheet(f"{param} Probabilities")
        n = NUM_STATES[param]
        hx = PARAM_HEX[param]
        wsp.merge_cells(f"A1:{get_column_letter(n+1)}1")
        tc = wsp["A1"]
        tc.value = f"{param} — State Probability Evolution (j=1 to 30)"
        tc.font = Font(bold=True, size=12, color=WH)
        tc.fill = _fill(hx)
        tc.alignment = Alignment(horizontal="center", vertical="center")
        wsp.row_dimensions[1].height = 24
        _cs(wsp, 2, 1, "Step (j)", bold=True, fill=_fill(hx), fc=WH)
        for si in range(1, n + 1):
            _cs(wsp, 2, si + 1,
                f"S{si}: {STATE_LABELS[param][si-1][:28]}",
                bold=True, fill=_fill(hx), fc=WH)
        for ri, j in enumerate(range(1, 31), 3):
            pvec = predictions[param].get(j, [float('nan')] * n)
            bg = _fill(ALT) if ri % 2 == 0 else None
            _cs(wsp, ri, 1, j, bold=True, fill=bg)
            for si in range(n):
                val = float(pvec[si]) if len(pvec) > si else float('nan')
                _cs(wsp, ri, si + 2,
                    round(val, 4) if not np.isnan(val) else "N/A", fill=bg)
        wsp.column_dimensions["A"].width = 10
        for si in range(1, n + 1):
            wsp.column_dimensions[get_column_letter(si + 1)].width = max(
                16, len(STATE_LABELS[param][si - 1][:28]) + 4)
        wsp.conditional_formatting.add(
            f"B3:{get_column_letter(n+1)}32",
            ColorScaleRule(
                start_type="num", start_value=0, start_color="FFFFFF",
                end_type="num",   end_value=1,   end_color=hx,
            )
        )
        wsp.freeze_panes = "B3"

    # Sheet — State Definitions
    wsr = wb.create_sheet("State Definitions")
    wsr.merge_cells("A1:C1")
    rc = wsr["A1"]
    rc.value = "Q-System Parameter State Definitions"
    rc.font = Font(bold=True, size=13, color=WH)
    rc.fill = _fill(DK)
    rc.alignment = Alignment(horizontal="center", vertical="center")
    wsr.row_dimensions[1].height = 26
    row_r = 2
    for param in PARAMS:
        wsr.merge_cells(f"A{row_r}:C{row_r}")
        ph = wsr[f"A{row_r}"]
        ph.value = f"{param} — {PARAM_DESCRIPTIONS[param]}"
        ph.font = Font(bold=True, size=10, color=WH)
        ph.fill = _fill(PARAM_HEX[param])
        ph.alignment = Alignment(horizontal="left")
        wsr.row_dimensions[row_r].height = 20
        row_r += 1
        for ci, h in enumerate(["State", "Rating", "Description"], 1):
            _cs(wsr, row_r, ci, h, bold=True, fill=_fill("C0C0C0"), fc="000000")
        row_r += 1
        for si, (lbl, rat) in enumerate(
                zip(STATE_LABELS[param], RATINGS[param]), 1):
            bg = _fill(ALT) if si % 2 == 0 else None
            _cs(wsr, row_r, 1, si, fill=bg)
            _cs(wsr, row_r, 2, rat, fill=bg)
            _cs(wsr, row_r, 3, lbl, fill=bg, align="left")
            row_r += 1
        row_r += 1
    for ci, w in enumerate([10, 12, 52], 1):
        wsr.column_dimensions[get_column_letter(ci)].width = w

    buf = io.BytesIO()
    wb.save(buf)
    buf.seek(0)
    return buf.getvalue()


