def plot_q_trend(pred_ratings):
    steps = list(range(1, 31))
    q_vals = [compute_q(pred_ratings, j) for j in steps]
    qualities = [classify_q(q) for q in q_vals]
    colors = [Q_BAND_COLORS.get(ql, "#888") for ql in qualities]
    fig = go.Figure()
    bands = [
        (0.001, 0.01,  "Exceptionally poor", "rgba(123,0,0,0.07)"),
        (0.01,  0.1,   "Extremely poor",     "rgba(192,57,43,0.07)"),
        (0.1,   1,     "Very poor",          "rgba(231,76,60,0.07)"),
        (1,     4,     "Poor",               "rgba(230,126,34,0.07)"),
        (4,     10,    "Fair",               "rgba(241,196,15,0.07)"),
        (10,    40,    "Good",               "rgba(46,204,113,0.07)"),
        (40,    100,   "Very good",          "rgba(26,188,156,0.07)"),
        (100,   400,   "Extremely good",     "rgba(52,152,219,0.07)"),
    ]
    for lo, hi, lbl, fill in bands:
        fig.add_hrect(
            y0=lo, y1=hi, fillcolor=fill, line_width=0,
            annotation_text=lbl, annotation_position="right",
            annotation=dict(font_size=9, font_color="#555", xanchor="left"),
        )
    fig.add_trace(go.Scatter(
        x=steps, y=q_vals, mode="lines+markers",
        line=dict(width=3, color="#1a1a2e"),
        marker=dict(size=8, color=colors, line=dict(width=1.5, color="white")),
        name="Q value",
        hovertemplate="<b>Step j=%{x}</b><br>Q = %{y:.4f}<br>%{text}<extra></extra>",
        text=qualities,
    ))
    fig.update_layout(
        title=dict(
            text="<b>Predicted Q-Value Evolution</b> — j=1 to 30 chainage steps",
            font=dict(size=15, color="#1a1a2e"), x=0.01,
        ),
        xaxis=dict(title="Chainage step (j)", tickmode="linear", dtick=2,
                   showgrid=True, gridcolor="#e8ecf0"),
        yaxis=dict(title="Q Value (log scale)", type="log",
                   showgrid=True, gridcolor="#e8ecf0"),
        plot_bgcolor="white", paper_bgcolor="white",
        height=460, margin=dict(l=60, r=160, t=55, b=55),
        hovermode="x unified",
    )
    return fig


def plot_param_predictions(pred_ratings):
    steps = list(range(1, 31))
    palette = ["#4361EE", "#3A0CA3", "#7209B7", "#F72585", "#4CC9F0", "#27AE60"]
    fig = make_subplots(
        rows=3, cols=2,
        subplot_titles=[f"{PARAM_ICONS[p]} {p}" for p in PARAMS],
        vertical_spacing=0.10, horizontal_spacing=0.08,
    )
    for i, (param, color) in enumerate(zip(PARAMS, palette)):
        r, c = divmod(i, 2)
        vals = [pred_ratings.get(param, {}).get(j, np.nan) for j in steps]
        fig.add_trace(go.Scatter(
            x=steps, y=vals, mode="lines+markers",
            line=dict(width=2.5, color=color),
            marker=dict(size=5, color=color),
            name=param, showlegend=False,
            hovertemplate=f"<b>{param}</b> j=%{{x}}: %{{y:.3f}}<extra></extra>",
        ), row=r + 1, col=c + 1)
    fig.update_layout(
        title=dict(text="<b>Parameter Rating Predictions</b> — j=1 to 30",
                   font=dict(size=14, color="#1a1a2e"), x=0.01),
        height=680, plot_bgcolor="white", paper_bgcolor="white", showlegend=False,
    )
    fig.update_xaxes(showgrid=True, gridcolor="#e8ecf0", dtick=5)
    fig.update_yaxes(showgrid=True, gridcolor="#e8ecf0")
    return fig


def plot_probability_heatmap(predictions, param):
    if param not in predictions:
        return None
    n = NUM_STATES[param]
    steps = sorted(predictions[param].keys())
    z = [[round(float(v), 4) for v in predictions[param][j]] for j in steps]
    xlabels = [f"S{i+1}: {STATE_LABELS[param][i][:20]}" for i in range(n)]
    fig = go.Figure(go.Heatmap(
        z=z, x=xlabels, y=[f"j={j}" for j in steps],
        colorscale="Blues", zmin=0, zmax=1,
        text=[[f"{v:.3f}" for v in row] for row in z],
        texttemplate="%{text}", textfont=dict(size=8),
        hovertemplate="Step %{y}<br>%{x}<br>Prob: %{z:.4f}<extra></extra>",
        colorbar=dict(title="Prob.", len=0.8),
    ))
    fig.update_layout(
        title=dict(
            text=f"<b>{PARAM_ICONS[param]} {param}</b> — State Probability Heatmap",
            font=dict(size=13, color="#1a1a2e"),
        ),
        xaxis=dict(title="State", tickangle=-35, tickfont=dict(size=8)),
        yaxis=dict(title="Step (j)", autorange="reversed", tickfont=dict(size=9)),
        height=530, margin=dict(l=60, r=40, t=55, b=130),
        plot_bgcolor="white", paper_bgcolor="white",
    )
    return fig


def plot_initial_state(row_vectors):
    palette = ["#4361EE", "#3A0CA3", "#7209B7", "#F72585", "#4CC9F0", "#27AE60"]
    fig = make_subplots(
        rows=2, cols=3,
        subplot_titles=[f"{PARAM_ICONS[p]} {p}" for p in PARAMS],
        vertical_spacing=0.16, horizontal_spacing=0.08,
    )
    for i, (param, color) in enumerate(zip(PARAMS, palette)):
        r, c = divmod(i, 3)
        rv = row_vectors[param]
        fig.add_trace(go.Bar(
            x=[f"S{si+1}" for si in range(len(rv))], y=rv,
            marker_color=color, opacity=0.85, name=param, showlegend=False,
            hovertemplate=f"<b>{param}</b> %{{x}}: %{{y:.3f}}<extra></extra>",
        ), row=r + 1, col=c + 1)
    fig.update_layout(
        title=dict(
            text="<b>Initial State Probability Distribution</b>",
            font=dict(size=14, color="#1a1a2e"), x=0.01,
        ),
        height=480, plot_bgcolor="white", paper_bgcolor="white",
    )
    fig.update_yaxes(range=[0, 1.05], showgrid=True, gridcolor="#eee")
    return fig


